import java.util.PriorityQueue;

public static long solve(long m, long n, long[][] waitCost) {
    if (m == 0 || n == 0) return 0;

    // Directions: right (0, 1), down (1, 0)
    int[][] dirs = {{0, 1}, {1, 0}};

    // Priority queue for Dijkstra's algorithm: [i, j, step, cost]
    PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[3], b[3]));
    pq.offer(new long[]{0, 0, 1, (0 + 1) * (0 + 1)});

    // Visited array to keep track of minimal cost for each (i, j, step % 2)
    // Since steps alternate between odd and even, we can use step % 2
    long[][][] minCost = new long[(int)m][(int)n][2];
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            minCost[i][j][0] = Long.MAX_VALUE;
            minCost[i][j][1] = Long.MAX_VALUE;
        }
    }
    minCost[0][0][1] = (0 + 1) * (0 + 1); // step starts at 1 (odd)

    while (!pq.isEmpty()) {
        long[] curr = pq.poll();
        int i = (int)curr[0];
        int j = (int)curr[1];
        long step = curr[2];
        long cost = curr[3];

        if (i == m - 1 && j == n - 1) {
            return cost;
        }

        if (step % 2 == 1) {
            // Odd step: move right or down
            for (int[] dir : dirs) {
                int ni = i + dir[0];
                int nj = j + dir[1];
                if (ni < m && nj < n) {
                    long newCost = cost + (ni + 1) * (nj + 1);
                    long newStep = step + 1;
                    int parity = (int)(newStep % 2);
                    if (newCost < minCost[ni][nj][parity]) {
                        minCost[ni][nj][parity] = newCost;
                        pq.offer(new long[]{ni, nj, newStep, newCost});
                    }
                }
            }
        } else {
            // Even step: wait
            long newCost = cost + waitCost[i][j];
            long newStep = step + 1;
            int parity = (int)(newStep % 2);
            if (newCost < minCost[i][j][parity]) {
                minCost[i][j][parity] = newCost;
                pq.offer(new long[]{i, j, newStep, newCost});
            }
        }
    }

    return -1; // unreachable
}
